import React, { useEffect, useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { getReports, updateReport } from '../services/api';

function ReportDetail() {
  const { id } = useParams();
  const [report, setReport] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem('user'));

  useEffect(() => {
    fetchReport();
  }, [id]);

  const fetchReport = async () => {
    try {
      const response = await getReports();
      const foundReport = response.data.find(r => r.id === parseInt(id));
      
      if (foundReport) {
        // Check if user has permission to view this report
        if (user.role !== 'admin' && foundReport.user_id !== user.id) {
          setError('You do not have permission to view this report');
          setReport(null);
        } else {
          setReport(foundReport);
        }
      } else {
        setError('Report not found');
      }
    } catch (err) {
      console.error('Error fetching report:', err);
      setError('Failed to load report');
    } finally {
      setLoading(false);
    }
  };

  const handleStatusChange = async (newStatus) => {
    try {
      await updateReport(id, { status: newStatus });
      setReport({ ...report, status: newStatus });
    } catch (err) {
      alert('Failed to update status');
    }
  };

  if (loading) return <div className="text-center mt-5">Loading...</div>;
  if (error) return <div className="alert alert-danger">{error}</div>;
  if (!report) return <div className="alert alert-warning">Report not found</div>;

  // Double-check permission
  if (user.role !== 'admin' && report.user_id !== user.id) {
    return <div className="alert alert-danger">You do not have permission to view this report</div>;
  }

  const getStatusBadge = (status) => {
    const classes = {
      Pending: 'bg-warning',
      'In Progress': 'bg-info',
      Resolved: 'bg-success'
    };
    return <span className={`badge ${classes[status] || 'bg-secondary'}`}>{status}</span>;
  };

  const isAdmin = user && user.role === 'admin';

  return (
    <div className="container">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2>Report #{report.id}</h2>
        <Link to={isAdmin ? '/admin/reports' : '/dashboard'} className="btn btn-secondary">
          Back to {isAdmin ? 'Reports' : 'Dashboard'}
        </Link>
      </div>

      <div className="card mb-4">
        <div className="card-header bg-primary text-white">
          <h4 className="mb-0">{report.title}</h4>
        </div>
        <div className="card-body">
          <div className="row">
            <div className="col-md-6">
              <p><strong>Type:</strong> {report.report_type}</p>
              <p><strong>Room:</strong> {report.room}</p>
              <p><strong>Priority:</strong> 
                <span className={`badge ${report.priority === 'High' ? 'bg-danger' : report.priority === 'Medium' ? 'bg-warning' : 'bg-success'} ms-2`}>
                  {report.priority}
                </span>
              </p>
              <p><strong>Status:</strong> {getStatusBadge(report.status)}</p>
            </div>
            <div className="col-md-6">
              <p><strong>Reported by:</strong> {report.author_name}</p>
              <p><strong>Date:</strong> {new Date(report.created_at).toLocaleString()}</p>
              {report.submitted_date && <p><strong>Submitted:</strong> {new Date(report.submitted_date).toLocaleString()}</p>}
              {report.in_progress_date && <p><strong>In Progress:</strong> {new Date(report.in_progress_date).toLocaleString()}</p>}
              {report.resolved_date && <p><strong>Resolved:</strong> {new Date(report.resolved_date).toLocaleString()}</p>}
            </div>
          </div>
          
          <div className="mt-3">
            <h5>Description:</h5>
            <p>{report.description}</p>
          </div>

         {report.photo_path && (
  <div className="mt-3">
    <h5>Photo:</h5>
    <img 
      src={`http://localhost:5000/static/uploads/${report.photo_path}`} 
      alt="Report" 
      className="img-fluid rounded shadow" 
      style={{ maxHeight: '400px', cursor: 'pointer' }}
      onClick={() => window.open(`http://localhost:5000/static/uploads/${report.photo_path}`, '_blank')}
      onError={(e) => {
        e.target.onerror = null;
        e.target.src = 'https://via.placeholder.com/400x300?text=Image+Not+Found';
      }}
    />
    <p className="text-muted small mt-2">Click image to view full size</p>
  </div>
)}
        </div>
      </div>

      {/* Admin actions */}
      {isAdmin && (
        <div className="card">
          <div className="card-header bg-warning">
            <h5 className="mb-0">Admin Actions</h5>
          </div>
          <div className="card-body">
            <label className="form-label">Update Status:</label>
            <div className="d-flex gap-2">
              <button 
                className="btn btn-warning" 
                onClick={() => handleStatusChange('Pending')}
                disabled={report.status === 'Pending'}
              >
                Pending
              </button>
              <button 
                className="btn btn-info" 
                onClick={() => handleStatusChange('In Progress')}
                disabled={report.status === 'In Progress'}
              >
                In Progress
              </button>
              <button 
                className="btn btn-success" 
                onClick={() => handleStatusChange('Resolved')}
                disabled={report.status === 'Resolved'}
              >
                Resolved
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default ReportDetail;
